function scoreResponse(response, keywords) {
  const lower = response.toLowerCase();
  const found  = keywords.filter(kw => lower.includes(kw.toLowerCase()));
  const missed = keywords.filter(kw => !lower.includes(kw.toLowerCase()));
  return { found, missed, pct: Math.round((found.length / keywords.length) * 100) };
}

async function runAITest(question, attempt = 0, modelId = "claude-haiku-4-5-20251001") {
  // Wait up to 3s for token getter to be initialized (race condition on first load)
  let waited = 0;
  while (!_getToken && waited < 3000) {
    await new Promise(r => setTimeout(r, 100));
    waited += 100;
  }
  const token = typeof _getToken === "function" ? await _getToken() : null;
  const res = await fetch("/api/chat", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      ...(token ? { "Authorization": `Bearer ${token}` } : {}),
    },
    body: JSON.stringify({
      model:    modelId,
      max_tokens: 800,
      system:   SYSTEM_PROMPT,
      messages: [{ role: "user", content: question }],
    }),
  });
  // 401 — token race condition, retry once after delay
  if (res.status === 401 && attempt === 0) {
    await new Promise(r => setTimeout(r, 1500));
    return runAITest(question, 1, modelId);
  }
  // Rate limited — wait and retry once
  if (res.status === 429 && attempt === 0) {
    await new Promise(r => setTimeout(r, 15000));
    return runAITest(question, 1, modelId);
  }
  if (!res.ok) {
    let msg = `HTTP ${res.status}`;
    try { const d = await res.json(); msg = d.error || msg; } catch {}
    throw new Error(msg);
  }
  const data = await res.json();
  if (data.error) throw new Error(data.error.message || JSON.stringify(data.error));
  return data.content?.filter(b => b.type === "text").map(b => b.text).join("") || "";
}

// Generate new questions via AI
async function generateNewQuestions(category, difficulty, count = 3, modelId = "claude-haiku-4-5-20251001") {
  const res = await fetch("/api/chat", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      model: modelId,
      max_tokens: 1200,
      system: SYSTEM_PROMPT,
      messages: [{ role: "user", content:
        `Generate ${count} new ${difficulty}-difficulty evaluation questions for the "${category}" category of Phoenix Controls HVAC knowledge testing. ` +
        `Return ONLY a JSON array, no other text. Each item: {"q":"question text","keywords":["kw1","kw2","kw3","kw4"],"diff":"${difficulty}","points":${difficulty==="basic"?8:difficulty==="standard"?12:18}}. ` +
        `Questions must be specific, technical, and testable with keyword matching. Keywords should be 3-6 specific technical terms the answer must contain.`
      }],
    }),
  });
  if (!res.ok) throw new Error(`HTTP ${res.status}`);
  const data = await res.json();
  const text = data.content?.filter(b => b.type === "text").map(b => b.text).join("") || "";
  const match = text.match(/\[[\s\S]*\]/);
  if (!match) throw new Error("Could not parse generated questions");
  return JSON.parse(match[0]);
}

