// ═══════════════════════════════════════════════════════════════════════════
// FIELD REPORT
// ═══════════════════════════════════════════════════════════════════════════
function FieldReport() {
  const STORAGE_KEY = "phx:field_reports";
  const EMPTY = { site: "", building: "", room: "", date: new Date().toISOString().slice(0,10), tech: "", equipment: "", problem: "", diagnosis: "", solution: "", parts: "", followUp: "", status: "open" };
  const [reports, setReports] = useState([]);
  const [form, setForm] = useState(EMPTY);
  const [view, setView] = useState("list"); // "list" | "new" | "detail"
  const [selected, setSelected] = useState(null);
  const [search, setSearch] = useState("");

  useEffect(() => {
    (async () => {
      try { const r = await window.storage.get(STORAGE_KEY); if (r) setReports(JSON.parse(r.value)); } catch {}
      try { const ls = localStorage.getItem(STORAGE_KEY); if (ls) setReports(JSON.parse(ls)); } catch {}
    })();
  }, []);

  const save = async (list) => {
    setReports(list);
    try { await window.storage.set(STORAGE_KEY, JSON.stringify(list)); } catch {}
    try { localStorage.setItem(STORAGE_KEY, JSON.stringify(list)); } catch {}
  };

  const submitReport = async () => {
    if (!form.site || !form.problem) return alert("Site and problem description are required.");
    const report = { ...form, id: Date.now(), created: new Date().toISOString() };
    await save([report, ...reports]);
    setForm(EMPTY);
    setView("list");
  };

  const exportPDF = (r) => {
    const lines = [
      `PHOENIX CONTROLS — FIELD SERVICE REPORT`,
      `Generated: ${new Date().toLocaleString()}`,
      ``,
      `SITE: ${r.site}   BUILDING: ${r.building}   ROOM: ${r.room}`,
      `DATE: ${r.date}   TECHNICIAN: ${r.tech}   STATUS: ${r.status.toUpperCase()}`,
      ``,
      `EQUIPMENT:`,
      r.equipment,
      ``,
      `PROBLEM REPORTED:`,
      r.problem,
      ``,
      `DIAGNOSIS:`,
      r.diagnosis,
      ``,
      `SOLUTION APPLIED:`,
      r.solution,
      ``,
      `PARTS USED / NEEDED:`,
      r.parts,
      ``,
      `FOLLOW-UP REQUIRED:`,
      r.followUp,
    ].join("\n");
    const blob = new Blob([lines], { type: "text/plain" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `FieldReport_${r.site.replace(/\s+/g,"_")}_${r.date}.txt`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const copyReport = (r) => {
    const lines = [
      `FIELD SERVICE REPORT — ${r.site} ${r.date}`,
      `Tech: ${r.tech} | Room: ${r.room} | Status: ${r.status.toUpperCase()}`,
      ``,`Equipment: ${r.equipment}`,
      `Problem: ${r.problem}`,
      `Diagnosis: ${r.diagnosis}`,
      `Solution: ${r.solution}`,
      `Parts: ${r.parts}`,
      `Follow-up: ${r.followUp}`,
    ].join("\n");
    navigator.clipboard?.writeText(lines).then(() => alert("Report copied to clipboard!")).catch(() => alert("Copy failed — use Export instead"));
  };

  const filtered = reports.filter(r =>
    [r.site, r.room, r.tech, r.problem, r.equipment].join(" ").toLowerCase().includes(search.toLowerCase())
  );

  const F = { label: { fontSize:11, color:C.textDim, marginBottom:3, display:"block" }, input: { width:"100%", background:C.card, border:`1px solid ${C.border}`, borderRadius:8, padding:"7px 10px", color:C.text, fontSize:12, fontFamily:"inherit", boxSizing:"border-box" } };

  if (view === "new") return (
    <div style={{ padding:20, maxWidth:700, margin:"0 auto" }}>
      <div style={{ display:"flex", alignItems:"center", gap:10, marginBottom:16 }}>
        <button onClick={() => setView("list")} style={{ background:"transparent", border:`1px solid ${C.border}`, borderRadius:8, padding:"4px 10px", color:C.textMid, fontSize:11, cursor:"pointer" }}>← Back</button>
        <div style={{ fontSize:15, fontWeight:700, color:C.text }}>New Field Report</div>
      </div>
      <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:10, marginBottom:10 }}>
        {[["Site / Customer","site"],["Building","building"],["Room / Zone","room"],["Date","date"],["Technician","tech"]].map(([label,key]) => (
          <div key={key}>
            <label style={F.label}>{label}</label>
            <input type={key==="date"?"date":"text"} value={form[key]} onChange={e=>setForm(p=>({...p,[key]:e.target.value}))} style={F.input} />
          </div>
        ))}
        <div>
          <label style={F.label}>Status</label>
          <select value={form.status} onChange={e=>setForm(p=>({...p,status:e.target.value}))} style={F.input}>
            <option value="open">Open</option>
            <option value="in-progress">In Progress</option>
            <option value="resolved">Resolved</option>
            <option value="parts-pending">Parts Pending</option>
          </select>
        </div>
      </div>
      {[["Equipment Found (model numbers, serial numbers)","equipment","textarea"],["Problem Reported","problem","textarea"],["Diagnosis","diagnosis","textarea"],["Solution Applied","solution","textarea"],["Parts Used / Needed (part numbers)","parts","textarea"],["Follow-Up Required","followUp","textarea"]].map(([label,key,type]) => (
        <div key={key} style={{ marginBottom:10 }}>
          <label style={F.label}>{label}</label>
          <textarea value={form[key]} onChange={e=>setForm(p=>({...p,[key]:e.target.value}))} rows={3}
            style={{...F.input, resize:"vertical", minHeight:60}} />
        </div>
      ))}
      <button onClick={submitReport} style={{ width:"100%", background:"rgba(83,74,183,0.25)", border:`1px solid ${C.purpleBorder}`, borderRadius:10, padding:"11px", color:C.purpleLight, fontSize:13, fontWeight:600, cursor:"pointer", marginTop:4 }}>
        💾 Save Report
      </button>
    </div>
  );

  if (view === "detail" && selected) return (
    <div style={{ padding:20, maxWidth:700, margin:"0 auto" }}>
      <div style={{ display:"flex", alignItems:"center", gap:10, marginBottom:16, flexWrap:"wrap" }}>
        <button onClick={() => setView("list")} style={{ background:"transparent", border:`1px solid ${C.border}`, borderRadius:8, padding:"4px 10px", color:C.textMid, fontSize:11, cursor:"pointer" }}>← Back</button>
        <div style={{ fontSize:14, fontWeight:700, color:C.text, flex:1 }}>{selected.site} — {selected.room}</div>
        <span style={{ fontSize:10, background: selected.status==="resolved" ? "rgba(74,222,128,0.15)" : "rgba(251,191,36,0.15)", color: selected.status==="resolved" ? "#4ade80" : "#fbbf24", border: `1px solid ${selected.status==="resolved" ? "rgba(74,222,128,0.3)" : "rgba(251,191,36,0.3)"}`, borderRadius:10, padding:"2px 8px" }}>{selected.status.toUpperCase()}</span>
        <button onClick={() => copyReport(selected)} style={{ background:"transparent", border:`1px solid ${C.border}`, borderRadius:8, padding:"4px 10px", color:C.textMid, fontSize:11, cursor:"pointer" }}>↗ Share</button>
        <button onClick={() => exportPDF(selected)} style={{ background:"rgba(83,74,183,0.15)", border:`1px solid ${C.purpleBorder}`, borderRadius:8, padding:"4px 10px", color:C.purpleLight, fontSize:11, cursor:"pointer" }}>⬇ Export</button>
        <button onClick={() => { if (window.confirm("Delete this report?")) { const updated = reports.filter(r=>r.id!==selected.id); save(updated); setView("list"); }}} style={{ background:"rgba(248,113,113,0.1)", border:"1px solid rgba(248,113,113,0.25)", borderRadius:8, padding:"4px 10px", color:"#f87171", fontSize:11, cursor:"pointer" }}>Delete</button>
      </div>
      <div style={{ background:C.card, border:`1px solid ${C.purpleBorder}`, borderRadius:12, padding:18, display:"flex", flexDirection:"column", gap:14 }}>
        <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr 1fr", gap:10 }}>
          {[["Date",selected.date],["Tech",selected.tech],["Building",selected.building]].map(([l,v])=>(
            <div key={l}><div style={{ fontSize:10, color:C.textDim, marginBottom:2 }}>{l}</div><div style={{ fontSize:12, color:C.text }}>{v||"—"}</div></div>
          ))}
        </div>
        {[["Equipment",selected.equipment],["Problem",selected.problem],["Diagnosis",selected.diagnosis],["Solution",selected.solution],["Parts",selected.parts],["Follow-Up",selected.followUp]].map(([label,val])=> val ? (
          <div key={label}>
            <div style={{ fontSize:10, color:C.textDim, marginBottom:3, textTransform:"uppercase", letterSpacing:"0.06em" }}>{label}</div>
            <div style={{ fontSize:12, color:C.text, lineHeight:1.6, whiteSpace:"pre-wrap" }}>{val}</div>
          </div>
        ) : null)}
      </div>
    </div>
  );

  return (
    <div style={{ padding:20, maxWidth:700, margin:"0 auto" }}>
      <div style={{ display:"flex", alignItems:"center", gap:10, marginBottom:14, flexWrap:"wrap" }}>
        <div style={{ fontSize:15, fontWeight:700, color:C.text, flex:1 }}>📋 Field Reports</div>
        <button onClick={() => { setForm(EMPTY); setView("new"); }} style={{ background:"rgba(83,74,183,0.2)", border:`1px solid ${C.purpleBorder}`, borderRadius:9, padding:"6px 14px", color:C.purpleLight, fontSize:12, fontWeight:600, cursor:"pointer" }}>+ New Report</button>
      </div>
      <input placeholder="Search reports…" value={search} onChange={e=>setSearch(e.target.value)}
        style={{ width:"100%", background:C.card, border:`1px solid ${C.border}`, borderRadius:9, padding:"8px 12px", color:C.text, fontSize:12, marginBottom:12, boxSizing:"border-box" }} />
      {filtered.length === 0 && <div style={{ textAlign:"center", color:C.textDim, fontSize:12, paddingTop:30 }}>No reports yet. Create one to document field work.</div>}
      <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
        {filtered.map(r => (
          <div key={r.id} onClick={() => { setSelected(r); setView("detail"); }} style={{ background:C.card, border:`1px solid ${C.border}`, borderRadius:10, padding:"12px 14px", cursor:"pointer", display:"flex", alignItems:"flex-start", gap:12 }}>
            <div style={{ flex:1 }}>
              <div style={{ display:"flex", alignItems:"center", gap:8, marginBottom:4 }}>
                <span style={{ fontSize:13, fontWeight:600, color:C.text }}>{r.site}</span>
                <span style={{ fontSize:10, color:C.textDim }}>· {r.room} · {r.date}</span>
                <span style={{ fontSize:9, background: r.status==="resolved"?"rgba(74,222,128,0.15)":"rgba(251,191,36,0.15)", color:r.status==="resolved"?"#4ade80":"#fbbf24", borderRadius:8, padding:"1px 6px", marginLeft:"auto" }}>{r.status}</span>
              </div>
              <div style={{ fontSize:11, color:C.textMid, whiteSpace:"nowrap", overflow:"hidden", textOverflow:"ellipsis" }}>{r.problem?.substring(0,120)}</div>
              {r.tech && <div style={{ fontSize:10, color:C.textDim, marginTop:3 }}>Tech: {r.tech}</div>}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

